/* ******************************************* START
 * *********************************************** */
/* Libraries, Definitions and Global Declarations */
#include "main.h"
#include "EngTrModel.h"
#include "functions.h"
#include "lcd.h"
#include "ports.h"
#include "pwm.h"
#include "timer.h"
#include "uart.h"
#include <stdio.h>

volatile double brake_torque = 0;
volatile double adc_value_percent = 0;
volatile uint8_t transmit_ready = 0;

void Transmit_Data(void);

void TIM3_IRQHandler(void) {
  if (TIM3->SR & (0x1UL << 0U)) {
    TIM3->SR &= ~(0x1UL << 0U);

    adc_value_percent = 1.5f + ((float)adc_value / 4095.0f) * 98.5f;
    EngTrModel_U.Throttle = adc_value_percent;
    EngTrModel_U.BrakeTorque = brake_torque;
    EngTrModel_step();
    transmit_ready = 1;
  }
}

int main(void) {
  SystemClock_Config();
  USART1_Init();
  ADC1_GPIO_Init();
  ADC1_Init();
  TIM3_Init();
  TIM3_40ms_Interrupt_Config();
  EXT_Button_Init();
  PWM_GPIO_Init();
  TIM2_PWM_Init();

  LCD_Init();
  LCD_Set_Cursor(1, 1);
  LCD_Put_Str("Transmision Tractor");
  LCD_Set_Cursor(2, 3);
  Delay_1sec_CPU();
  Delay_1sec_CPU();
  LCD_Clear();

  EngTrModel_initialize();

  for (;;) {
    if (transmit_ready) {
      transmit_ready = 0;
      Transmit_Data();
    }

    if (EXT_BUTTON) {
      Delay_10ms_CPU();
      if (EXT_BUTTON) {
        brake_torque = 100.0;
      }
    } else {
      brake_torque = 0;
    }

    double duty = (EngTrModel_Y.VehicleSpeed / 140.0) * 100.0;
    Change_Duty_Cycle(duty);

    char line[17];
    snprintf(line, sizeof(line), "Ac:%4.0f   G:%u", (double)adc_value,
             (unsigned)EngTrModel_Y.Gear);
    LCD_Set_Cursor(1, 1);
    LCD_Put_Str(line);

    snprintf(line, sizeof(line), "RPM:%8.1f  ", EngTrModel_Y.EngineSpeed);
    LCD_Set_Cursor(2, 1);
    LCD_Put_Str(line);
  }
}

void Transmit_Data(void) {
  char buffer[32];
  uint16_t len;

  len = snprintf(buffer, sizeof(buffer), "VS:%.2f\r\n",
                 EngTrModel_Y.VehicleSpeed);
  USART1_Transmit((uint8_t *)buffer, len);
  len =
      snprintf(buffer, sizeof(buffer), "ES:%.2f\r\n", EngTrModel_Y.EngineSpeed);
  USART1_Transmit((uint8_t *)buffer, len);

  len = snprintf(buffer, sizeof(buffer), "GR:%.2f\r\n", EngTrModel_Y.Gear);
  USART1_Transmit((uint8_t *)buffer, len);
}
